odel', '1', '5'), ('14', 'Fluid precision delivery control system for critical health care applications', 'https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?w=800', 'Creates precision fluid delivery systems for medical IVs using automated dosage control.', '', 'https://github.com/mathworks/Infusion-Pump/', '1', '5'), ('15', 'IOT based Energy meter', 'https://how2electronics.com/wp-content/uploads/2020/12/IoT-Electricity-Energy-Meter.jpg', 'Tracks energy consumption in real-time via IoT-enabled smart meters for optimized power usage.', '', 'https://github.com/habiburrahman-mu/IOT-Based-Prepaid-Energy-Meter-and-load-shedding-and-Roadlight-Control', '1', '5'), ('16', 'Electric Vehicle Battery Management System with charge monitor & fire protection', 'https://d1gymyavdvyjgt.cloudfront.net/drive/images/uploads/headers/ws_cropper/1_0x0_790x520_0x520_electric-car-batteries-made-of.jpg', 'Designs EV battery systems with charge monitoring and thermal protection to prevent fires.', '', 'https://github.com/Greg-Fordyce/evBMS', '1', '5'), ('17', 'Smart safe helmet for Bike Activation', 'https://i.pinimg.com/originals/89/3a/93/893a935d0c22a85217ab60c3b63afa4d.png', 'Integrates helmet-wearing detection with bike ignition systems to enforce rider safety.', '', 'https://github.com/charantanuj/DESIGN-AND-STUDY-OF-SMART-HELMET-FOR-COLLISION-DETERRENCE ', '1', '5'), ('18', 'Domestic Fire Fighting Robot', 'https://i.ytimg.com/vi/1-FafDx9gVw/maxresdefault.jpg', 'Builds an autonomous firefighting robot for domestic use with heat sensors and extinguishing mechanisms.', '', 'https://github.com/RoCTCNJ/FireFighter', '1', '5'), ('19', 'Facelog: Modernizing Student Attendance Management with Facial Recognition', 'https://images.unsplash.com/photo-1587620962725-abab7fe55159?w=800', 'Automates attendance tracking using facial recognition technology for educational institutions.', '', 'https://github.com/RATHISHMANIVANNAN/Smart-Attendance-Management-System', '1', '5'), ('20', 'Analyse